const x = [];
const y = [];
const z = [];
const numPoints = 70; // Number of points along each axis
const range = 5; // Range from -range to +range

// Generate x and y values
for (let i = 0; i <= numPoints; i++) {
    const val = (i / numPoints) * (2 * range) - range; // Scale from -range to +range
    x.push(val);
    y.push(val);
}

// Generate z values (2D array)
for (let i = 0; i < x.length; i++) {
    z.push([]);
    for (let j = 0; j < y.length; j++) {
        // Calculate z = sin(x) * cos(y)
        z[i].push(Math.sin(x[i]) * Math.cos(y[j]));
    }
}

return [{
    type: 'surface',
    x: x,
    y: y,
    z: z,
    colorscale: 'Viridis', // A vibrant and perceptually uniform colorscale
    lighting: {
        ambient: 0.7, // Overall light intensity
        diffuse: 0.8, // Diffuse reflection coefficient
        specular: 0.2, // Specular reflection coefficient
        roughness: 0.5, // Roughness of the surface
        fresnel: 0.05 // Fresnel effect (light reflection based on angle)
    },
    contours: {
        z: {
            show: true,
            start: -1, // Start of contour lines
            end: 1, // End of contour lines
            size: 0.2, // Step between contour lines
            highlight: false // Do not highlight a specific contour
        }
    }
}];
